# ── Logging setup ─────────────────────────────────────────────────────
def _setup_logging() -> logging.Logger:
    """Configure file + console logging for SiteSentinel Matrix Pro."""
    log_dir = Path(sys.executable).parent if getattr(sys, "frozen", False)               else Path(__file__).parent
    log_file = log_dir / "sitesentinel.log"
    
    fmt = logging.Formatter(
        "%(asctime)s  %(levelname)-8s  %(name)s — %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S"
    )
    
    root_logger = logging.getLogger("sitesentinel")
    root_logger.setLevel(logging.DEBUG)
    
    # Rotating file handler (max 5 MB, keep 3 backups)
    try:
        from logging.handlers import RotatingFileHandler
        fh = RotatingFileHandler(log_file, maxBytes=5_242_880, backupCount=3, encoding="utf-8")
        fh.setLevel(logging.DEBUG)
        fh.setFormatter(fmt)
        root_logger.addHandler(fh)
    except Exception:
        pass  # Can't write log file — silently skip (read-only FS, etc.)
    
    # Console handler (WARNING+ only, avoids polluting stdout in production)
    ch = logging.StreamHandler(sys.stderr)
    ch.setLevel(logging.WARNING)
    ch.setFormatter(fmt)
    root_logger.addHandler(ch)
    
    return root_logger

log = _setup_logging()

if sys.platform.startswith("win"):
    try:
        sys.stdout.reconfigure(encoding="utf-8")
        sys.stderr.reconfigure(encoding="utf-8")
    except Exception as _e:
        log.debug("[sitesentinel] suppressed: %s", _e)


