def _app_dir() -> Path:
    """Return app base directory — works for both .py and PyInstaller bundles."""
    if getattr(sys, "frozen", False):
        # PyInstaller frozen executable — use the folder containing the .exe
        return Path(sys.executable).parent
    return Path(__file__).parent


VIEWPORTS = {
    "desktop": {"width": 1920, "height": 1080, "label": "Desktop (1920×1080)"},
    "mac":     {"width": 1440, "height": 900,  "label": "Mac (1440×900)"},
    "laptop":  {"width": 1366, "height": 768,  "label": "Laptop (1366×768)"},
    "mobile":  {"width": 430,  "height": 932,  "label": "Mobile (430×932)"},
}

SEV = {
    "CRITICAL": "CRITICAL",
    "HIGH":     "HIGH",
    "MEDIUM":   "MEDIUM",
    "LOW":      "LOW",
    "INFO":     "INFO",
    "PASS":     "PASS",
}

MAX_PDF_FILES = 10
MAX_PDF_PAGES = 300


def _tc(tc_id, category, name, result, severity, detail="", expected="", actual=""):
    """Build a structured test-case dict."""
    return {
        "TC ID":     tc_id,
        "Category":  category,
        "Test Name": name,
        "Result":    result,
        "Severity":  severity if result != "PASS" else "PASS",
        "Detail":    detail,
        "Expected":  expected,
        "Actual":    actual,
    }


