# DETAILED CONSOLE MESSAGE PARSER
# ══════════════════════════════════════════════════════════════════════

def _describe_console_message(raw_msg: str) -> dict:
    msg   = raw_msg.strip()
    upper = msg.upper()

    result = {
        "level":       "ERROR" if "[ERROR]" in upper else "WARNING",
        "short_title": msg[:80],
        "detail":      msg,
        "severity":    SEV["HIGH"],
        "category":    "Console Error",
        "fix_hint":    "Review the browser console for full stack trace.",
    }

    net_match = re.search(
        r"(GET|POST|PUT|DELETE|PATCH|HEAD)\s+(https?://\S+)\s+(\d{3})", msg, re.I)
    if net_match or re.search(r"failed to (load|fetch|retrieve)", msg, re.I):
        url_m  = re.search(r"https?://[^\s\"']+", msg)
        url    = url_m.group(0) if url_m else "(unknown URL)"
        code_m = re.search(r"\b(4\d{2}|5\d{2})\b", msg)
        code   = code_m.group(0) if code_m else "unknown"
        method = net_match.group(1).upper() if net_match else "Resource"

        if code.startswith("4"):
            desc = (f"{method} request to '{url}' returned HTTP {code}. "
                    f"The resource does not exist or access is forbidden.")
            fix  = (f"Verify the URL '{url}' is correct and the server returns 200. "
                    f"HTTP 404 means not found; 403 means forbidden (check CORS/auth).")
            sev  = SEV["HIGH"] if code == "404" else SEV["CRITICAL"]
        elif code.startswith("5"):
            desc = (f"{method} request to '{url}' returned HTTP {code}. "
                    f"The server encountered an internal error.")
            fix  = "Check server-side logs. HTTP 5xx indicates a backend problem."
            sev  = SEV["CRITICAL"]
        else:
            desc = f"Network request to '{url}' failed to load."
            fix  = "Check if the resource URL is reachable and CORS headers are set."
            sev  = SEV["HIGH"]

        result.update({"category": "Network Error",
                        "short_title": f"[{code}] {url[:60]}",
                        "detail": desc, "severity": sev, "fix_hint": fix})
        return result

    if re.search(r"content.security.policy|csp|refused to (load|execute|connect|frame|apply)",
                 msg, re.I):
        blocked_m = re.search(r"\"([^\"]+)\"", msg)
        blocked   = blocked_m.group(1) if blocked_m else "(resource)"
        directive_m = re.search(
            r"(script-src|style-src|img-src|connect-src|frame-src|font-src|"
            r"default-src|object-src|media-src)", msg, re.I)
        directive = directive_m.group(1) if directive_m else "CSP directive"
        desc = (f"Content Security Policy blocked '{blocked}'. "
                f"The '{directive}' policy did not allow this resource.")
        fix  = (f"Add '{blocked}' to the '{directive}' allowlist in your CSP header.")
        result.update({"category": "CSP Violation",
                        "short_title": f"CSP blocked: {blocked[:55]}",
                        "detail": desc, "severity": SEV["HIGH"], "fix_hint": fix})
        return result

    if re.search(r"(TypeError|ReferenceError|SyntaxError|RangeError)", msg):
        err_type_m = re.search(
            r"(TypeError|ReferenceError|SyntaxError|RangeError):?\s*([^\n\r]+)", msg)
        err_type = err_type_m.group(1) if err_type_m else "JavaScript Error"
        err_msg  = err_type_m.group(2).strip() if err_type_m else msg[:80]
        file_m   = re.search(r"(https?://[^\s\"':]+\.js[^\s\"']*)", msg)
        file_ref = f" in {file_m.group(1).split('/')[-1]}" if file_m else ""
        line_m   = re.search(r":(\d+):(\d+)", msg)
        line_ref = f" at line {line_m.group(1)}, col {line_m.group(2)}" if line_m else ""

        if err_type == "TypeError":
            desc = (f"JavaScript TypeError{file_ref}{line_ref}: '{err_msg}'. "
                    f"This usually means a variable or property is null/undefined.")
            fix  = ("Add null checks before accessing properties/calling methods.")
        elif err_type == "ReferenceError":
            desc = (f"JavaScript ReferenceError{file_ref}{line_ref}: '{err_msg}'. "
                    f"A variable or function name is used before it is defined.")
            fix  = ("Declare the variable before using it. Check for typos.")
        elif err_type == "SyntaxError":
            desc = (f"JavaScript SyntaxError{file_ref}{line_ref}: '{err_msg}'.")
            fix  = (f"Open DevTools Sources tab and inspect{file_ref} near{line_ref}.")
        else:
            desc = (f"JavaScript {err_type}{file_ref}{line_ref}: '{err_msg}'.")
            fix  = "Review the identified script file and line for the root cause."

        result.update({"category": f"JS {err_type}",
                        "short_title": f"{err_type}: {err_msg[:55]}",
                        "detail": desc, "severity": SEV["HIGH"], "fix_hint": fix})
        return result

    if re.search(r"deprecat|deprecated|will be removed", msg, re.I):
        api_m   = re.search(r"'([^']+)'", msg)
        api_ref = f"'{api_m.group(1)}'" if api_m else "a deprecated API"
        desc = (f"Deprecation warning: {api_ref} is deprecated and may be removed "
                f"in a future browser version.")
        fix  = (f"Replace {api_ref} with its modern equivalent. Consult MDN Web Docs.")
        result.update({"category": "Deprecation Warning",
                        "short_title": f"Deprecated: {api_ref[:55]}",
                        "detail": desc, "severity": SEV["MEDIUM"], "fix_hint": fix})
        return result

    if re.search(r"cors|cross.origin|access.control", msg, re.I):
        url_m = re.search(r"https?://[^\s\"']+", msg)
        url   = url_m.group(0) if url_m else "(unknown origin)"
        desc  = (f"CORS error for '{url}'. The server did not include the required "
                 f"'Access-Control-Allow-Origin' header.")
        fix   = (f"On the server at '{url}', add the header: "
                 f"'Access-Control-Allow-Origin: your-domain.com'.")
        result.update({"category": "CORS Error",
                        "short_title": f"CORS blocked: {url[:55]}",
                        "detail": desc, "severity": SEV["CRITICAL"], "fix_hint": fix})
        return result

    if re.search(r"mixed content|http.*https|insecure", msg, re.I):
        url_m = re.search(r"http://[^\s\"']+", msg)
        url   = url_m.group(0) if url_m else "(HTTP resource)"
        desc  = (f"Mixed content warning: The HTTPS page is loading '{url}' over HTTP.")
        fix   = f"Change the resource URL to use HTTPS."
        result.update({"category": "Mixed Content",
                        "short_title": f"Mixed content: {url[:55]}",
                        "detail": desc, "severity": SEV["HIGH"], "fix_hint": fix})
        return result

    if "[WARNING]" in upper or "warn" in msg.lower():
        desc = (f"Browser warning: {msg[:200]}.")
        result.update({"category": "Browser Warning",
                        "short_title": msg[:70],
                        "detail": desc, "severity": SEV["MEDIUM"],
                        "fix_hint": "Review the warning message and apply recommended fixes."})
        return result

    desc = (f"Browser console error: {msg[:300]}. "
            f"Open DevTools → Console tab to see the full stack trace.")
    result.update({"detail": desc,
                   "fix_hint": ("Open browser DevTools (F12) → Console tab.")})
    return result


# ══════════════════════════════════════════════════════════════════════
# PDF TEXT EXTRACTION
# ══════════════════════════════════════════════════════════════════════

def extract_pdf_text(pdf_paths: list) -> tuple:
    combined_text = ""
    total_pages   = 0
    errors        = []

    for pdf_path in pdf_paths:
        path_str = str(pdf_path)
        basename = os.path.basename(path_str)
        extracted = False

        try:
            import fitz
            doc = fitz.open(path_str)
            page_count = min(len(doc), MAX_PDF_PAGES)
            for page_num in range(page_count):
                page = doc[page_num]
                text = page.get_text("text")
                combined_text += text + "\n"
                total_pages += 1
            doc.close()
            extracted = True
        except ImportError:
            pass
        except Exception as e:
            errors.append(f"{basename} [PyMuPDF error]: {e}")

        if extracted:
            continue

        if not extracted:
            try:
                import pdfplumber
                with pdfplumber.open(path_str) as pdf:
                    page_count = min(len(pdf.pages), MAX_PDF_PAGES)
                    for page in pdf.pages[:page_count]:
                        text = page.extract_text() or ""
                        combined_text += text + "\n"
                        total_pages += 1
                extracted = True
            except ImportError:
                errors.append(
                    f"{basename}: Neither PyMuPDF nor pdfplumber is installed.\n"
                    f"  FIX → pip install PyMuPDF"
                )
            except Exception as e:
                errors.append(f"{basename} [pdfplumber error]: {e}")

    return combined_text, total_pages, errors


def keywords_from_text(text: str) -> list:
    tl = text.lower()
    phrases  = re.findall(r"\b([a-z][a-z0-9]+(?: [a-z][a-z0-9]+){1,3})\b", tl)
    phrases  = [p for p in phrases if len(p.split()) >= 2]
    tokens   = re.findall(r"[a-z][a-z0-9\-]{2,}", tl)
    acronyms = [a.lower() for a in re.findall(r"\b[A-Z]{2,}\b", text)]
    numbers  = re.findall(r"\b\d{4,}\b", text)

    STOP = {
        "this","that","with","from","have","been","will","they","their","there",
        "which","about","would","could","should","more","also","into","your",
        "what","when","were","some","each","than","then","them","these","those",
        "such","after","page","figure","table","section","chapter","the","and",
        "for","are","was","has","had","not","but","all",
    }

    seen, unique = set(), []
    for kw in acronyms + numbers + tokens + phrases[:150]:
        kw = kw.strip()
        if kw and kw not in seen and kw not in STOP and len(kw) >= 3:
            seen.add(kw)
            unique.append(kw)
    return unique


