    # ── Helper: draw score gauge on canvas ────────────────────────────
    def _lh_draw_gauge(self, canvas, score, color):
        """Draw a circular gauge. score=None → grey placeholder."""
        canvas.delete("all")
        cx, cy, r = 36, 36, 28
        # Background arc
        canvas.create_oval(cx-r, cy-r, cx+r, cy+r,
                           outline="#E5E7EB", width=6, fill="")
        if score is not None:
            # Score determines color: green/amber/red
            if score >= 90:   arc_col = "#059669"
            elif score >= 50: arc_col = "#D97706"
            else:             arc_col = "#DC2626"
            # Draw arc proportional to score
            extent = -360 * (score / 100)
            canvas.create_arc(cx-r, cy-r, cx+r, cy+r,
                              start=90, extent=extent,
                              outline=arc_col, width=6,
                              style="arc")
        # Center text
        txt = str(score) if score is not None else "?"
        canvas.create_text(cx, cy, text=txt,
                           font=("Segoe UI", 13, "bold"),
                           fill=color if score is not None else "#C1C7D0")

    # ── Lighthouse: write to log ───────────────────────────────────────
    def _lh_log_write(self, msg, tag=""):
        from datetime import datetime
        def _w():
            ts = datetime.now().strftime("%H:%M:%S")
            self._lh_log.config(state="normal")
            self._lh_log.insert("end", f"[{ts}]  {msg}\n", tag)
            self._lh_log.see("end")
            self._lh_log.config(state="disabled")
        self.root.after(0, _w)

    # ── Lighthouse: run audit ─────────────────────────────────────────
    def _lh_run(self):
        url = self._lh_url_var.get().strip()
        if not url.startswith("http"):
            messagebox.showwarning("Invalid URL",
                "Please enter a valid URL starting with http:// or https://")
            return

        active_cats = [k for k, v in self._lh_cats.items() if v.get()]
        if not active_cats:
            messagebox.showwarning("No Categories",
                "Please select at least one audit category.")
            return

        # Reset scores
        for key in self._lh_score_vars:
            self._lh_score_vars[key].set("—")
            self._lh_draw_gauge(self._lh_score_frames[key], None, "#C1C7D0")
        for key in self._lh_cwv_vars:
            self._lh_cwv_vars[key].set("—")
        for item in self._lh_tree.get_children():
            self._lh_tree.delete(item)

        self._lh_stop_event.clear()
        self._lh_run_btn.config(state="disabled")
        self._lh_stop_btn.config(state="normal")
        self._lh_status_var.set("🔄  Running Lighthouse audit…")

        threading.Thread(target=self._lh_run_thread,
                        args=(url, active_cats),
                        daemon=True).start()

    def _lh_stop(self):
        self._lh_stop_event.set()
        self._lh_status_var.set("⏹  Stopping…")

    def _lh_run_thread(self, url: str, categories: list):
        """Background thread: invoke lighthouse CLI and parse results."""
        import subprocess, json, tempfile, os, shutil
        from pathlib import Path
        from datetime import datetime

        def _done(msg, ok=True):
            self.root.after(0, lambda: (
                self._lh_run_btn.config(state="normal"),
                self._lh_stop_btn.config(state="disabled"),
                self._lh_status_var.set(msg)
            ))

        # Check if lighthouse is installed
        lh_bin = shutil.which("lighthouse") or shutil.which("lighthouse.cmd")
        if not lh_bin:
            self._lh_log_write(
                "Lighthouse CLI not found. Install it with:", "warn")
            self._lh_log_write("  npm install -g lighthouse", "info")
            self._lh_log_write("Then verify with:  lighthouse --version", "info")
            _done("❌  Lighthouse not installed — see installation steps below", False)
            return

        self._lh_log_write(f"{'='*54}", "hdr")
        self._lh_log_write(f"  LIGHTHOUSE AUDIT", "hdr")
        self._lh_log_write(f"  URL:    {url}", "hdr")
        self._lh_log_write(f"  Device: {self._lh_device_var.get()}", "hdr")
        self._lh_log_write(f"  Cats:   {', '.join(categories)}", "hdr")
        self._lh_log_write(f"{'='*54}", "hdr")

        # Output file paths
        ts       = datetime.now().strftime("%Y%m%d_%H%M%S")
        out_dir  = _app_dir() / "reports"
        out_dir.mkdir(exist_ok=True)
        json_out = str(out_dir / f"lighthouse_{ts}.json")
        html_out = str(out_dir / f"lighthouse_{ts}.html")

        device_flag = "--emulated-form-factor=none" if             self._lh_device_var.get() == "Desktop" else             "--emulated-form-factor=mobile"

        cats_flag = f"--only-categories={','.join(categories)}"

        # Browser mode: headless or visible
        browser_mode = getattr(self, "_lh_browser_mode", None)
        if browser_mode and browser_mode.get() == "visible":
            chrome_flags = "--no-sandbox --disable-gpu"
            self._lh_log_write("Browser mode: Visible (Chrome window will open)", "info")
        else:
            chrome_flags = "--headless --no-sandbox --disable-gpu"
            self._lh_log_write("Browser mode: Headless (no visible window)", "info")

        cmd = [
            lh_bin, url,
            "--output=json,html",
            f"--output-path={out_dir / f'lighthouse_{ts}'}",
            f"--chrome-flags={chrome_flags}",
            device_flag, cats_flag,
            "--quiet",
        ]

        self._lh_log_write(f"Running: {lh_bin} {url}", "info")
        self._lh_log_write("Please wait — this takes 30–60 seconds…", "info")

        try:
            proc = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                text=True
            )

            # Stream output
            for line in proc.stdout:
                if self._lh_stop_event.is_set():
                    proc.terminate()
                    self._lh_log_write("Audit stopped by user.", "warn")
                    _done("⏹  Stopped")
                    return
                line = line.rstrip()
                if line:
                    tag = ("err" if "error" in line.lower() else
                           "warn" if "warn" in line.lower() else
                           "ok"  if "pass" in line.lower() else "")
                    self._lh_log_write(line, tag)

            proc.wait()

            # Load JSON results
            json_file = out_dir / f"lighthouse_{ts}.report.json"
            if not json_file.exists():
                # Try alternate naming
                json_file = out_dir / f"lighthouse_{ts}.json"

            if json_file.exists():
                self._lh_json_path = str(json_file)
                with open(json_file, encoding="utf-8") as f:
                    data = json.load(f)
                self.root.after(0, lambda d=data: self._lh_populate_results(d))
                _done(f"✅  Audit complete — reports saved to reports/")
                self._lh_log_write("✅  Audit complete!", "ok")
                self._lh_log_write(f"   JSON: {json_file}", "info")
                html_file = out_dir / f"lighthouse_{ts}.report.html"
                if html_file.exists():
                    self._lh_html_path = str(html_file)
                    self._lh_log_write(f"   HTML: {html_file}", "info")
            else:
                self._lh_log_write(
                    "⚠  Report file not found. Check that Chrome is installed.", "warn")
                _done("⚠  Report file not found", False)

        except FileNotFoundError:
            self._lh_log_write("❌  Could not execute lighthouse binary.", "err")
            _done("❌  Execution failed", False)
        except Exception as ex:
            self._lh_log_write(f"❌  Error: {ex}", "err")
            log.warning("[Lighthouse] %s", ex)
            _done(f"❌  {str(ex)[:60]}", False)

    def _lh_populate_results(self, data: dict):
        """Parse Lighthouse JSON report and populate UI."""
        cats = data.get("categories", {})
        audits = data.get("audits", {})

        # Populate score gauges
        score_map = {
            "performance":    ("performance",    self.C_BLUE),
            "accessibility":  ("accessibility",  self.C_GREEN),
            "best-practices": ("best-practices", self.C_PURPLE),
            "seo":            ("seo",            self.C_RED),
            "pwa":            ("pwa",            self.C_TEAL),
        }
        for cat_id, (key, col) in score_map.items():
            cat = cats.get(cat_id)
            if cat and key in self._lh_score_vars:
                score = round((cat.get("score") or 0) * 100)
                self._lh_score_vars[key].set(str(score))
                self._lh_draw_gauge(self._lh_score_frames[key], score, col)

        # Populate Core Web Vitals
        cwv_map = {
            "lcp":   "largest-contentful-paint",
            "fid":   "total-blocking-time",
            "cls":   "cumulative-layout-shift",
            "fcp":   "first-contentful-paint",
            "si":    "speed-index",
            "tbt":   "total-blocking-time",
            "ttfb":  "server-response-time",
        }
        for cwv_key, audit_key in cwv_map.items():
            a = audits.get(audit_key, {})
            dv = a.get("displayValue", "")
            if dv and cwv_key in self._lh_cwv_vars:
                self._lh_cwv_vars[cwv_key].set(str(dv)[:12])

        # Populate treeview with audit findings
        for item in self._lh_tree.get_children():
            self._lh_tree.delete(item)

        cat_labels = {
            "performance":   "Performance",
            "accessibility": "Accessibility",
            "best-practices":"Best Practices",
            "seo":           "SEO",
            "pwa":           "PWA",
        }

        for cat_id, cat_label in cat_labels.items():
            cat = cats.get(cat_id)
            if not cat:
                continue
            audit_refs = cat.get("auditRefs", [])
            for ref in audit_refs:
                a = audits.get(ref["id"], {})
                if not a:
                    continue
                sc    = a.get("score")
                title = a.get("title", ref["id"])[:55]
                dv    = str(a.get("displayValue", ""))[:30]
                impact = ref.get("weight", 0)

                if sc is None:
                    tag, sc_txt = "info", "N/A"
                elif sc >= 0.9:
                    tag, sc_txt = "pass", f"{round(sc*100)}"
                elif sc >= 0.5:
                    tag, sc_txt = "warn", f"{round(sc*100)}"
                else:
                    tag, sc_txt = "fail", f"{round(sc*100)}"

                # Only show non-passing or weight > 0
                if sc is not None and sc >= 0.9 and impact == 0:
                    continue

                self._lh_tree.insert("", "end", tags=(tag,),
                    values=(cat_label, title, sc_txt,
                            dv, f"w={impact}" if impact else ""))

    def _lh_open_json(self):
        if self._lh_json_path and os.path.exists(self._lh_json_path):
            webbrowser.open(self._lh_json_path)
        else:
            messagebox.showinfo("No Report",
                "No JSON report available yet. Run an audit first.")

    def _lh_open_html(self):
        if self._lh_html_path and os.path.exists(self._lh_html_path):
            if sys.platform == "win32":
                os.startfile(self._lh_html_path)
            elif sys.platform == "darwin":
                subprocess.Popen(["open", self._lh_html_path])
            else:
                webbrowser.open(self._lh_html_path)
        else:
            messagebox.showinfo("No Report",
                "No HTML report available yet. Run an audit first.")

    def _lh_clear(self):
        self._lh_log.config(state="normal")
        self._lh_log.delete("1.0", tk.END)
        self._lh_log.config(state="disabled")
        for key in self._lh_score_vars:
            self._lh_score_vars[key].set("—")
            self._lh_draw_gauge(self._lh_score_frames[key], None, "#C1C7D0")
        for key in self._lh_cwv_vars:
            self._lh_cwv_vars[key].set("—")
        for item in self._lh_tree.get_children():
            self._lh_tree.delete(item)
        self._lh_status_var.set("")
        self._lh_json_path = None
        self._lh_html_path = None

    def _lh_export_report(self):
        """Generate and save a professional HTML Lighthouse report."""
        import json as _json
        if not self._lh_json_path or not os.path.exists(self._lh_json_path):
            messagebox.showinfo("No Data",
                "No Lighthouse JSON found.\nRun an audit first, then export.")
            return
        try:
            data = _json.loads(open(self._lh_json_path, encoding="utf-8").read())
        except Exception as e:
            messagebox.showerror("Read Error", str(e))
            return

        from tkinter import filedialog
        ts   = datetime.now().strftime("%Y%m%d_%H%M%S")
        path = filedialog.asksaveasfilename(
            initialfile=f"lighthouse_report_{ts}.html",
            defaultextension=".html",
            filetypes=[("HTML Report", "*.html"), ("All", "*.*")])
        if not path:
            return

        html = _build_lighthouse_html_report(data)
        try:
            with open(path, "w", encoding="utf-8") as f:
                f.write(html)
            self._lh_log_write(f"✓ HTML report saved: {path}", "ok")
            self._lh_status_var.set(f"✅  Report saved")
            messagebox.showinfo("Report Saved",
                f"Professional HTML report saved to:\n{path}")
            webbrowser.open(path)
        except Exception as e:
            messagebox.showerror("Save Error", str(e))

