    # ── DevOps: Test Connection ────────────────────────────────────────
    def _devops_test_connection(self, org: str, proj: str, pat: str) -> tuple:
        """Test Azure DevOps REST API connection. Returns (ok, message)."""
        import urllib.request, urllib.error, base64, json

        try:
            # Basic auth: username="" + PAT as password
            credentials = base64.b64encode(f":{pat}".encode()).decode()
            url = f"{org}/{urllib.parse.quote(proj)}/_apis/projects?api-version=7.1"
            req = urllib.request.Request(url)
            req.add_header("Authorization", f"Basic {credentials}")
            req.add_header("Content-Type", "application/json")

            with urllib.request.urlopen(req, timeout=10) as resp:
                data = json.loads(resp.read().decode())
                return True, f"Project '{proj}' found. API v7.1 ✓"
        except urllib.error.HTTPError as e:
            if e.code == 401:
                return False, "Authentication failed — check your PAT and org URL."
            elif e.code == 404:
                return False, f"Project '{proj}' not found — check the project name."
            else:
                return False, f"HTTP {e.code}: {e.reason}"
        except Exception as ex:
            return False, f"Connection error: {str(ex)[:80]}"

    # ── DevOps: Push User Stories → Work Items ─────────────────────────
    def _devops_push_stories_thread(self, org: str, proj: str,
                                     pat: str, dlg):
        """Background thread: push User Stories as Work Items."""
        import urllib.request, urllib.error, base64, json

        credentials = base64.b64encode(f":{pat}".encode()).decode()
        headers = {
            "Authorization": f"Basic {credentials}",
            "Content-Type":  "application/json-patch+json",
        }

        pushed = 0
        errors = 0
        proj_enc = urllib.parse.quote(proj)

        for story in self._aistory_stories:
            ac_text = "\n".join(story.get("ac", []))
            body = json.dumps([
                {"op": "add", "path": "/fields/System.Title",
                 "value": story["story"]},
                {"op": "add", "path": "/fields/System.Description",
                 "value": f"<b>Epic:</b> {story['epic']}<br>"
                          f"<b>Story Points:</b> {story['points']}<br><br>"
                          f"<b>Acceptance Criteria:</b><br>"
                          f"<pre>{ac_text}</pre>"},
                {"op": "add", "path": "/fields/Microsoft.VSTS.Common.Priority",
                 "value": {"High": 1, "Medium": 2, "Low": 3}.get(story["priority"], 2)},
                {"op": "add", "path": "/fields/System.Tags",
                 "value": f"SiteSentinel; {story['epic']}"},
            ]).encode()

            url = (f"{org}/{proj_enc}/_apis/wit/workitems/"
                   f"$User%20Story?api-version=7.1")
            try:
                req = urllib.request.Request(url, data=body, method="POST")
                for k, v in headers.items():
                    req.add_header(k, v)
                with urllib.request.urlopen(req, timeout=15) as resp:
                    result = json.loads(resp.read().decode())
                    wi_id = result.get("id", "?")
                    story["devops_wi_id"] = wi_id
                    pushed += 1
            except Exception as ex:
                errors += 1
                log.warning("[DevOps] push story %s: %s", story["id"], ex)

        def _done():
            self._devops_push_status.set(
                f"✅  {pushed} stories pushed to DevOps."
                + (f"  ⚠ {errors} errors." if errors else ""))
            self._aistory_step_vars["devops"].set(
                f"✅ 5. DevOps ({pushed} synced)")
            if pushed:
                messagebox.showinfo("Stories Pushed",
                    f"✅  {pushed} User Stories created as Work Items in Azure DevOps!\n"
                    f"{'⚠ ' + str(errors) + ' stories had errors.' if errors else ''}\n\n"
                    f"Go to Azure DevOps → Boards → Backlogs to see them.",
                    parent=dlg)
        self.root.after(0, _done)

    # ── DevOps: Push Test Cases → Test Plans ──────────────────────────
    def _devops_push_tcs_thread(self, org: str, proj: str,
                                 pat: str, dlg):
        """Background thread: create Test Plan + Suites + Test Cases in DevOps."""
        import urllib.request, urllib.error, base64, json
        from datetime import datetime

        credentials = base64.b64encode(f":{pat}".encode()).decode()
        headers_json = {
            "Authorization": f"Basic {credentials}",
            "Content-Type":  "application/json",
        }
        headers_patch = {
            "Authorization": f"Basic {credentials}",
            "Content-Type":  "application/json-patch+json",
        }
        proj_enc = urllib.parse.quote(proj)

        def _api(method, url, body=None, patch=False):
            data = json.dumps(body).encode() if body else None
            req  = urllib.request.Request(url, data=data, method=method)
            hdrs = headers_patch if patch else headers_json
            for k, v in hdrs.items():
                req.add_header(k, v)
            with urllib.request.urlopen(req, timeout=15) as r:
                return json.loads(r.read().decode())

        try:
            stamp    = datetime.now().strftime("%Y-%m-%d %H:%M")
            plan_name = f"SiteSentinel Matrix Pro — {stamp}"

            # 1. Create Test Plan
            self.root.after(0, lambda: self._devops_tc_status.set(
                "🔄  Creating Test Plan…"))
            plan_url  = (f"{org}/{proj_enc}/_apis/testplan/plans"
                         f"?api-version=7.1")
            plan_resp = _api("POST", plan_url,
                              {"name": plan_name,
                               "areaPath": proj,
                               "iteration": proj})
            plan_id = plan_resp["id"]

            # 2. Get default root suite
            suite_url   = (f"{org}/{proj_enc}/_apis/testplan/plans/"
                           f"{plan_id}/suites?api-version=7.1")
            suites_resp = _api("GET", suite_url)
            root_suite  = suites_resp["value"][0]["id"]

            # 3. Group TCs by Epic → create one suite per epic
            epics = {}
            for tc in self._aistory_tcs:
                story = next((s for s in self._aistory_stories
                               if s["id"] == tc["story_id"]), None)
                epic = story["epic"] if story else "General"
                epics.setdefault(epic, []).append(tc)

            pushed_tc = 0
            for epic_name, tcs in epics.items():
                # Create suite for this epic
                suite_create_url = (f"{org}/{proj_enc}/_apis/testplan/plans/"
                                    f"{plan_id}/suites?api-version=7.1")
                suite_resp = _api("POST", suite_create_url, {
                    "suiteType": "staticTestSuite",
                    "name": epic_name[:255],
                    "parentSuite": {"id": root_suite},
                })
                suite_id = suite_resp["id"]

                for tc in tcs:
                    steps_html = "".join(
                        f"<step id='{i+1}' type='ActionStep'>"
                        f"<parameterizedString isformatted='true'>{s}</parameterizedString>"
                        f"<parameterizedString isformatted='true'>"
                        f"{tc.get('expected','') if i==len(tc.get('steps',[]))-1 else ''}"
                        f"</parameterizedString></step>"
                        for i, s in enumerate(tc.get("steps", []))
                    )

                    # Create Test Case Work Item
                    tc_wi_url = (f"{org}/{proj_enc}/_apis/wit/workitems/"
                                 f"$Test%20Case?api-version=7.1")
                    tc_body = [
                        {"op": "add", "path": "/fields/System.Title",
                         "value": tc["title"][:255]},
                        {"op": "add", "path": "/fields/Microsoft.VSTS.TCM.Steps",
                         "value": f"<steps id='0'>{steps_html}</steps>"},
                        {"op": "add", "path": "/fields/System.Tags",
                         "value": f"SiteSentinel; {tc['type']}"},
                    ]
                    # Link to story Work Item if we have the DevOps ID
                    story_obj = next((s for s in self._aistory_stories
                                      if s["id"] == tc["story_id"]), None)
                    if story_obj and story_obj.get("devops_wi_id"):
                        tc_body.append({
                            "op": "add",
                            "path": "/relations/-",
                            "value": {
                                "rel": "Microsoft.VSTS.Common.TestedBy-Reverse",
                                "url": (f"{org}/_apis/wit/workitems/"
                                        f"{story_obj['devops_wi_id']}"),
                            }
                        })

                    try:
                        req2 = urllib.request.Request(
                            tc_wi_url,
                            data=json.dumps(tc_body).encode(),
                            method="POST")
                        for k, v in headers_patch.items():
                            req2.add_header(k, v)
                        with urllib.request.urlopen(req2, timeout=15) as r2:
                            wi_resp = json.loads(r2.read().decode())
                            tc["devops_tc_id"] = wi_resp["id"]
                            pushed_tc += 1
                    except Exception as ex:
                        log.warning("[DevOps] push TC %s: %s", tc["tc_id"], ex)

            def _done_tc():
                self._devops_tc_status.set(
                    f"✅  {pushed_tc} test cases pushed. Plan ID: {plan_id}")
                self._aistory_step_vars["devops"].set(
                    f"✅ 5. DevOps (Plan {plan_id})")
                messagebox.showinfo("Test Cases Pushed",
                    f"✅  Azure DevOps Test Plan created!\n\n"
                    f"Plan Name: {plan_name}\n"
                    f"Plan ID:   {plan_id}\n"
                    f"Test Cases: {pushed_tc} pushed\n\n"
                    f"Go to Azure DevOps → Test Plans to see them.",
                    parent=dlg)
            self.root.after(0, _done_tc)

        except Exception as ex:
            msg = str(ex)[:120]
            log.warning("[DevOps] push TCs error: %s", ex)
            self.root.after(0, lambda: (
                self._devops_tc_status.set(f"❌  {msg}"),
                messagebox.showerror("DevOps Error",
                    f"Failed to push Test Cases:\n{msg}", parent=dlg)
            ))

    # ── DevOps: Pull Test Results ──────────────────────────────────────
    def _devops_pull_results_thread(self, org: str, proj: str,
                                     pat: str, dlg):
        """Background thread: pull latest test run results from DevOps."""
        import urllib.request, urllib.error, base64, json

        credentials = base64.b64encode(f":{pat}".encode()).decode()
        headers = {
            "Authorization": f"Basic {credentials}",
            "Content-Type":  "application/json",
        }
        proj_enc = urllib.parse.quote(proj)

        try:
            # Get most recent test runs
            runs_url = (f"{org}/{proj_enc}/_apis/test/runs"
                        f"?api-version=7.1&$top=10")
            req = urllib.request.Request(runs_url)
            for k, v in headers.items():
                req.add_header(k, v)

            with urllib.request.urlopen(req, timeout=15) as r:
                runs = json.loads(r.read().decode())

            if not runs.get("value"):
                self.root.after(0, lambda: self._devops_pull_status.set(
                    "⚠  No test runs found in this project."))
                return

            # Get results from most recent run
            latest_run    = runs["value"][0]
            run_id        = latest_run["id"]
            run_name      = latest_run.get("name", f"Run {run_id}")
            total_in_run  = latest_run.get("totalTests", 0)
            passed_in_run = latest_run.get("passedTests", 0)

            results_url = (f"{org}/{proj_enc}/_apis/test/runs/"
                           f"{run_id}/results?api-version=7.1&$top=200")
            req2 = urllib.request.Request(results_url)
            for k, v in headers.items():
                req2.add_header(k, v)

            with urllib.request.urlopen(req2, timeout=15) as r2:
                results_data = json.loads(r2.read().decode())

            # Map DevOps result outcomes to our status labels
            outcome_map = {
                "passed":       ("Pass",    "✅ Pass"),
                "failed":       ("Fail",    "❌ Fail"),
                "blocked":      ("Blocked", "⚠ Blocked"),
                "notExecuted":  ("Not Run", "—"),
                "notApplicable":("Manual",  "📋 Manual"),
            }

            updated = 0
            for res in results_data.get("value", []):
                tc_name   = res.get("testCase", {}).get("name", "")
                outcome   = res.get("outcome", "").lower()
                status, result_label = outcome_map.get(
                    outcome, ("Not Run", "—"))
                duration_ms = res.get("durationInMs", 0)

                # Match to our local test cases by title
                for tc in self._aistory_tcs:
                    if (tc["title"][:60].lower() in tc_name.lower() or
                            tc_name.lower() in tc["title"][:60].lower()):
                        tc["status"]   = status
                        tc["result"]   = result_label
                        tc["duration"] = f"{round(duration_ms)}ms"
                        updated += 1
                        break

            def _done_pull():
                self._devops_pull_status.set(
                    f"✅  Synced {updated} results from run '{run_name[:40]}'")
                self._aistory_step_vars["devops"].set(
                    f"✅ 5. DevOps ({updated} results synced)")
                # Refresh TC tree if story selected
                sel = self._ais_story_tree.selection()
                if sel:
                    self._ais_on_story_select(None)
                messagebox.showinfo("Results Pulled",
                    f"✅  Results synced from Azure DevOps!\n\n"
                    f"Run: {run_name}\n"
                    f"Total in run: {total_in_run}\n"
                    f"Passed: {passed_in_run}\n"
                    f"Matched to local TCs: {updated}\n\n"
                    f"Test case statuses updated in the middle pane.",
                    parent=dlg)
            self.root.after(0, _done_pull)

        except Exception as ex:
            msg = str(ex)[:120]
            log.warning("[DevOps] pull results error: %s", ex)
            self.root.after(0, lambda: (
                self._devops_pull_status.set(f"❌  {msg}"),
                messagebox.showerror("DevOps Error",
                    f"Failed to pull results:\n{msg}", parent=dlg)
            ))

