    # AUTOMATION REPORTS FILTER
    # ══════════════════════════════════════════════════════════════════

    def _apply_rpt_filter(self):
        """Filter the Automation Report History treeview based on combo selections."""
        type_filter   = getattr(self, "_rpt_filter",        None)
        date_filter   = getattr(self, "_rpt_date",          None)
        status_filter = getattr(self, "_rpt_status_filter", None)

        f_type   = type_filter.get()   if type_filter   else "All"
        f_date   = date_filter.get()   if date_filter   else "All time"
        f_status = status_filter.get() if status_filter else "All"

        # Build date cutoff
        now = datetime.now()
        cutoff = None
        if f_date == "Today":
            cutoff = now.replace(hour=0, minute=0, second=0, microsecond=0)
        elif f_date == "Last 7 days":
            cutoff = now - timedelta(days=7)
        elif f_date == "Last 30 days":
            cutoff = now - timedelta(days=30)
        elif f_date == "Last 90 days":
            cutoff = now - timedelta(days=90)

        # Map status filter to tag
        status_tag_map = {"Passed": "pass", "Failed": "fail"}

        # Clear tree
        for item in self._rpt_tree.get_children():
            self._rpt_tree.delete(item)

        # Re-insert matching rows
        matched = 0
        all_rows = getattr(self, "_rpt_all_rows", [])
        for row, tag in all_rows:
            # row = (run_id, type, suite, started, duration, passed, failed, status)
            row_type   = str(row[1])
            row_start  = str(row[3])  # "2026-05-DD HH:MM"
            row_status = str(row[7])  # "✅ Pass" or "❌ Fail"

            # Type filter
            if f_type != "All" and f_type.lower() not in row_type.lower():
                continue

            # Date filter
            if cutoff is not None:
                try:
                    row_dt = datetime.strptime(row_start[:16], "%Y-%m-%d %H:%M")
                    if row_dt < cutoff:
                        continue
                except ValueError:
                    pass

            # Status filter
            if f_status != "All":
                want_tag = status_tag_map.get(f_status, "")
                if want_tag and tag != want_tag:
                    continue

            self._rpt_tree.insert("", "end", tags=(tag,), values=row)
            matched += 1

        # Update the total runs KPI card
        if hasattr(self, "_rpt_total"):
            self._rpt_total.set(str(matched))

