    def _add_ug_button(self, parent: tk.Frame, tab_key: str,
                       color: str = None, side: str = "right") -> None:
        """Add a consistent '📖 User Guide' button to any tab header frame."""
        col = color or self.SW_ORANGE
        btn = tk.Button(
            parent,
            text="  📖  User Guide",
            bg=col, fg="white",
            font=("Segoe UI", 8, "bold"),
            relief="flat", cursor="hand2",
            padx=10, pady=4,
            activebackground=col,
            activeforeground="white",
            command=lambda: self._show_user_guide(tab_key),
        )
        btn.pack(side=side, padx=(8, 0))

    def _show_user_guide(self, tab_key: str) -> None:
        """
        Opens a clean, scrollable User Guide window for the given tab.
        Renders rich formatted content using a tkinter.Text widget.
        """
        data = self._UG_TAB_DATA.get(tab_key)
        if not data:
            return

        col   = data.get("color", self.SW_ORANGE)
        title = data.get("title", "User Guide")
        icon  = data.get("icon", "📖")
        tag   = data.get("tagline", "")

        # ── Window ────────────────────────────────────────────────────
        win = tk.Toplevel(self.root)
        win.title(f"📖  {title} — User Guide")
        win.geometry("680x720")
        win.resizable(True, True)
        win.configure(bg="#F0F2F5")
        win.lift()
        win.focus_force()

        # Center relative to main window
        try:
            rx = self.root.winfo_x() + (self.root.winfo_width()  - 680) // 2
            ry = self.root.winfo_y() + (self.root.winfo_height() - 720) // 2
            win.geometry(f"680x720+{rx}+{ry}")
        except Exception as _e:
            log.debug("[sitesentinel] suppressed: %s", _e)

        # ── Header bar ────────────────────────────────────────────────
        hdr = tk.Frame(win, bg=col)
        hdr.pack(fill="x")
        tk.Label(hdr, text=f"{icon}  {title}",
                 font=("Segoe UI", 15, "bold"),
                 bg=col, fg="white",
                 padx=20, pady=10).pack(side="left")
        tk.Button(hdr, text="✕  Close",
                  font=("Segoe UI", 9),
                  bg=col, fg="white", relief="flat",
                  cursor="hand2", padx=12, pady=6,
                  command=win.destroy).pack(side="right", padx=10)

        # Tagline
        tk.Label(win, text=tag,
                 font=("Segoe UI", 9, "italic"),
                 bg="#1E293B", fg="#94A3B8",
                 padx=20, pady=6,
                 anchor="w").pack(fill="x")

        # ── Scrollable body ───────────────────────────────────────────
        frame = tk.Frame(win, bg="#F0F2F5")
        frame.pack(fill="both", expand=True)

        vsb = ttk.Scrollbar(frame, orient="vertical",
                             style="SW.Vertical.TScrollbar")
        vsb.pack(side="right", fill="y")

        txt = tk.Text(
            frame,
            yscrollcommand=vsb.set,
            wrap="word",
            bg="white",
            fg="#1A2533",
            font=("Segoe UI", 10),
            padx=20, pady=14,
            relief="flat",
            borderwidth=0,
            cursor="arrow",
            state="normal",
            spacing1=2, spacing2=3, spacing3=4,
        )
        txt.pack(fill="both", expand=True)
        vsb.config(command=txt.yview)

        # ── Define text tags ──────────────────────────────────────────
        txt.tag_configure("sec_hdr",
            font=("Segoe UI", 11, "bold"),
            foreground="white",
            background=col,
            spacing1=12, spacing3=6,
            lmargin1=0, lmargin2=0,
            relief="flat",
        )
        txt.tag_configure("sec_hdr_pad",
            font=("Segoe UI", 11, "bold"),
            foreground=col,
            background="#F8FAFC",
            spacing1=10, spacing3=4,
            lmargin1=16, lmargin2=16,
            borderwidth=0,
        )
        txt.tag_configure("body",
            font=("Segoe UI", 10),
            foreground="#374151",
            lmargin1=24, lmargin2=24,
            spacing1=1, spacing3=1,
        )
        txt.tag_configure("bullet",
            font=("Segoe UI", 10),
            foreground="#374151",
            lmargin1=32, lmargin2=44,
            spacing1=2, spacing3=2,
        )
        txt.tag_configure("step",
            font=("Segoe UI", 10, "bold"),
            foreground=col,
            lmargin1=24, lmargin2=24,
            spacing1=3, spacing3=2,
        )
        txt.tag_configure("step_body",
            font=("Segoe UI", 10),
            foreground="#374151",
            lmargin1=50, lmargin2=50,
            spacing1=1, spacing3=3,
        )
        txt.tag_configure("tip",
            font=("Segoe UI", 10),
            foreground="#92400E",
            background="#FFFBEB",
            lmargin1=24, lmargin2=36,
            spacing1=3, spacing3=3,
        )
        txt.tag_configure("divider",
            font=("Segoe UI", 4),
            background="#E2E8F0",
            spacing1=0, spacing3=0,
        )
        txt.tag_configure("code",
            font=("Courier New", 9),
            foreground="#0369A1",
            background="#F0F9FF",
            lmargin1=28, lmargin2=28,
            spacing1=2, spacing3=2,
        )
        txt.tag_configure("empty",
            font=("Segoe UI", 5),
            spacing1=0, spacing3=0,
        )

        # ── Render content ────────────────────────────────────────────
        for (sec_title, lines) in data.get("sections", []):
            # Section header with colour bar
            txt.insert("end", f"  {sec_title}  \n", "sec_hdr_pad")
            txt.insert("end", "\n", "empty")

            for line in lines:
                stripped = line.strip()
                if stripped == "":
                    txt.insert("end", "\n", "empty")
                elif stripped.startswith("Step ") and "│" in stripped:
                    # Step line: "Step N │ description"
                    parts = stripped.split("│", 1)
                    step_lbl = parts[0].strip()
                    step_desc = parts[1].strip() if len(parts) > 1 else ""
                    txt.insert("end", f"  {step_lbl}  ", "step")
                    txt.insert("end", f"{step_desc}\n", "body")
                elif stripped.startswith("→"):
                    txt.insert("end", f"  {stripped}\n", "tip")
                elif "│" in stripped and not stripped.startswith("Step"):
                    # Table-style line
                    txt.insert("end", f"  {stripped}\n", "code")
                elif stripped.startswith("•") or stripped.startswith("  •"):
                    txt.insert("end", f"    {stripped}\n", "bullet")
                else:
                    txt.insert("end", f"  {stripped}\n", "body")

            # Divider between sections
            txt.insert("end", "\n", "empty")
            txt.insert("end", "─" * 72 + "\n", "divider")
            txt.insert("end", "\n", "empty")

        txt.config(state="disabled")

        # Bind mousewheel
        def _scroll(e):
            txt.yview_scroll(-1*(e.delta//120), "units")
        win.bind_all("<MouseWheel>", _scroll)
        win.bind("<Destroy>", lambda e: win.unbind_all("<MouseWheel>"))

    def _card(self, parent, title: str, subtitle: str = "",
              accent: str = None, P: dict = None) -> tk.Frame:
        accent  = accent or self.SW_ORANGE   # blue by default
        pack_kw = P if P is not None else {}
        outer   = tk.Frame(parent, bg=self.CARD_BG,
                           highlightbackground=self.CARD_BORDER,
                           highlightthickness=1)
        outer.pack(fill="x", **pack_kw)
        # Top accent line (3px)
        tk.Frame(outer, bg=accent, height=3).pack(fill="x")
        if title:
            hdr = tk.Frame(outer, bg=self.CARD_BG)
            hdr.pack(fill="x")
            tk.Label(hdr, text=title,
                     font=("Segoe UI", 10, "bold"),
                     bg=self.CARD_BG, fg=self.TEXT_PRI,
                     padx=16, pady=10).pack(side="left")
            if subtitle:
                tk.Label(hdr, text=subtitle,
                         font=("Segoe UI", 8),
                         bg=self.CARD_BG, fg=self.TEXT_MUT,
                         padx=4).pack(side="left", pady=10)
            # Clean grey divider — Atlassian style
            tk.Frame(outer, bg="#DFE1E6", height=1).pack(fill="x")
        body = tk.Frame(outer, bg=self.CARD_BG, padx=16, pady=12)
        body.pack(fill="both", expand=True)
        return body

    def _field_lbl(self, parent, text: str, required: bool = False):
        row = tk.Frame(parent, bg=self.CARD_BG); row.pack(fill="x", pady=(0,4))
        tk.Label(row, text=text, font=self.F_LBL,
                 bg=self.CARD_BG, fg=self.TEXT_SEC).pack(side="left")
        if required:
            tk.Label(row, text=" *", font=self.F_LBL,
                     bg=self.CARD_BG, fg=self.C_RED).pack(side="left")

    def _upload_pdfs(self):
        raw = filedialog.askopenfilenames(
            parent=self.root,
            title="Select PDF Reference Documents",
            filetypes=[("PDF Files", "*.pdf"), ("All Files", "*.*")])
        if isinstance(raw, str):
            paths = self.root.tk.splitlist(raw)
        else:
            paths = list(raw)
        if not paths: return
        added = 0
        for p in paths:
            if p not in self.pdf_paths and len(self.pdf_paths) < MAX_PDF_FILES:
                self.pdf_paths.append(p); added += 1
        if added:
            self._refresh_pdf_chips()
            self._log(f"📑  {added} PDF file(s) added.  Total: {len(self.pdf_paths)}", "purple")
        if len(self.pdf_paths) >= MAX_PDF_FILES:
            self._log(f"⚠️  Maximum of {MAX_PDF_FILES} PDFs reached.", "warn")

    def _refresh_pdf_chips(self):
        for w in self._pdf_chip_frame.winfo_children():
            w.destroy()
        if not self.pdf_paths:
            self._pdf_summary_lbl.config(
                text="No PDFs selected  —  click Browse PDFs to upload",
                fg=self.TEXT_MUT, font=self.F_SM)
            self._pdf_clear_btn.pack_forget(); return
        n = len(self.pdf_paths)
        self._pdf_summary_lbl.config(
            text=f"{n} PDF file(s) selected", fg=self.C_PURPLE,
            font=(self.F_SM[0], self.F_SM[1], "bold"))
        for path in self.pdf_paths:
            name = os.path.basename(path)
            chip = tk.Frame(self._pdf_chip_frame, bg="#FAF5FF",
                            highlightbackground=self.C_PURPLE_LIGHT, highlightthickness=1)
            chip.pack(fill="x", pady=(0,2))
            tk.Label(chip, text="📑", font=("Segoe UI", 9),
                     bg="#FAF5FF", padx=6).pack(side="left", pady=3)
            tk.Label(chip, text=name, font=self.F_SM,
                     bg="#FAF5FF", fg=self.C_PURPLE, anchor="w").pack(
                         side="left", fill="x", expand=True)
            def _remove(p=path):
                if p in self.pdf_paths: self.pdf_paths.remove(p)
                self._refresh_pdf_chips()
                self._log(f"Removed PDF: {os.path.basename(p)}", "warn")
            tk.Button(chip, text="✕", font=("Segoe UI", 8),
                      bg="#FAF5FF", fg=self.C_RED,
                      activebackground=self.C_RED_BG,
                      relief="flat", cursor="hand2",
                      command=_remove,
                      padx=6, pady=2).pack(side="right", padx=4, pady=2)
        self._pdf_clear_btn.pack(anchor="e", pady=(4,0))

    def _clear_pdfs(self):
        self.pdf_paths.clear()
        self._refresh_pdf_chips()
        self._log("All PDF files cleared.", "warn")

    def _upload_doc(self):
        path = filedialog.askopenfilename(
            parent=self.root, title="Select Reference Document",
            filetypes=[("Text Files", "*.txt"), ("All Files", "*.*")])
        if not path: return
        self.doc_path = path
        name = os.path.basename(path)
        self.doc_lbl.config(text=name, fg=self.C_GREEN,
                            font=(self.F_SM[0], self.F_SM[1], "bold"))
        self._doc_ico.config(text="✅")
        self._log(f"Reference document loaded: {name}", "ok")

    def _open_analyst_config(self):
        """Open a GUI dialog for QA Analyst to configure the scan parameters."""
        win = tk.Toplevel(self.root)
        win.title("QA Analyst Configuration")
        win.geometry("560x680")
        win.configure(bg=self.PAGE_BG)
        win.grab_set()

        hdr = tk.Frame(win, bg="#1B2A3B", height=52)
        hdr.pack(fill="x")
        tk.Label(hdr, text="  ⚙  QA Analyst Configuration",
                 font=("Segoe UI", 13, "bold"),
                 bg="#1B2A3B", fg="white").pack(side="left", pady=12, padx=12)

        body = tk.Frame(win, bg=self.PAGE_BG, padx=20, pady=14)
        body.pack(fill="both", expand=True)

        vars_dict = {}

        def field(label, key, default="", width=38):
            row = tk.Frame(body, bg=self.PAGE_BG)
            row.pack(fill="x", pady=(0, 8))
            tk.Label(row, text=label, font=self.F_SM, bg=self.PAGE_BG,
                     fg=self.TEXT_SEC, anchor="w").pack(fill="x")
            v = tk.StringVar(value=default)
            vars_dict[key] = v
            tk.Entry(row, textvariable=v, width=width, bg="white", fg=self.TEXT_PRI,
                     relief="flat", highlightbackground=self.CARD_BORDER_D,
                     highlightthickness=1, font=self.F_UI).pack(fill="x", ipady=4)
            return v

        field("Environment (staging / production / dev):", "environment", "staging")
        field("Test Scope (full / frontend / backend / api / accessibility / performance / security):",
              "scope", "full")
        field("Target Browsers (comma-separated: chrome, firefox, safari, edge):",
              "browsers", "chrome")
        field("Minimum Acceptable Site Health Score (0–100):", "min_health", "70")
        field("Max Page Load Time Budget (ms):", "perf_budget_ms", "4000")
        field("Max Page Weight Budget (KB):", "perf_budget_kb", "3000")
        field("WCAG Level (A / AA / AAA):", "wcag_level", "AA")
        field("Custom Keywords to Verify (comma-separated):", "extra_keywords", "")
        field("Test Cycle / Sprint Name:", "test_cycle", "Cycle-1")
        field("QA Analyst Name:", "analyst_name", "QA Team")
        field("Special Notes / Known Issues:", "analyst_notes", "")

        def save():
            cfg = {k: v.get().strip() for k, v in vars_dict.items()}
            # Store on self for use in scan
            self._analyst_config = cfg
            self._log_dispatch(
                f"  ✅  QA Analyst Config saved — "
                f"Analyst: {cfg['analyst_name']} | "
                f"Scope: {cfg['scope']} | "
                f"Env: {cfg['environment']} | "
                f"Min Score: {cfg['min_health']}")
            win.destroy()

        btn_row = tk.Frame(body, bg=self.PAGE_BG)
        btn_row.pack(fill="x", pady=(10, 0))
        tk.Button(btn_row, text="Save & Close",
                  bg=self.SW_ORANGE, fg="white",
                  activebackground=self.SW_ORANGE_HOV,
                  relief="flat", cursor="hand2",
                  font=self.F_H3, padx=18, pady=7,
                  command=save).pack(side="right")
        tk.Button(btn_row, text="Cancel",
                  bg=self.CARD_BG, fg=self.TEXT_SEC,
                  relief="flat", cursor="hand2", font=self.F_UI,
                  highlightbackground=self.CARD_BORDER_D, highlightthickness=1,
                  padx=14, pady=6, command=win.destroy).pack(side="right", padx=(0, 10))

    def _open_reports(self):
        folder = (_app_dir() / "reports").resolve()
        folder.mkdir(parents=True, exist_ok=True)
        self._log(f"Opening reports folder: {folder}", "info")
        try:
            if sys.platform.startswith("win"): os.startfile(str(folder))
            elif sys.platform == "darwin":     subprocess.Popen(["open",     str(folder)])
            else:                              subprocess.Popen(["xdg-open", str(folder)])
        except Exception as e:
            self._log(f"Could not open folder: {e}", "warn")

    def _open_screenshots(self):
        folder = (_app_dir() / "screenshots_marked").resolve()
        folder.mkdir(parents=True, exist_ok=True)
        self._log(f"Opening screenshots folder: {folder}", "info")
        try:
            if sys.platform.startswith("win"): os.startfile(str(folder))
            elif sys.platform == "darwin":     subprocess.Popen(["open",     str(folder)])
            else:                              subprocess.Popen(["xdg-open", str(folder)])
        except Exception as e:
            self._log(f"Could not open folder: {e}", "warn")

