if __name__ == "__main__":
    try:
        app = QAGUI()
        app.run()
    except Exception as _fatal:
        log.exception("SiteSentinel Matrix Pro fatal error — unhandled exception in main loop")
        try:
            import tkinter as _tk
            _r = _tk.Tk(); _r.withdraw()
            _tk.messagebox.showerror(
                f"SiteSentinel Matrix Pro {__version__} — Unexpected Error",
                f"A fatal error occurred and the application must close.\n\n"
                f"{type(_fatal).__name__}: {_fatal}\n\n"
                f"Details have been written to sitesentinel.log in the application folder."
            )
            _r.destroy()
        except Exception:
            pass
        sys.exit(1)